import{_ as r}from"./chunks/labledhome.DTdqm132.js";import{_ as t}from"./chunks/lablededit.6MKmj5Mq.js";import{_ as o,o as a,c as i,ae as n}from"./chunks/framework.C00B0EYs.js";const v=JSON.parse('{"title":"Interface Overview","description":"Read the application as a complete workflow before focusing on individual tools.","frontmatter":{"title":"Interface Overview","description":"Read the application as a complete workflow before focusing on individual tools."},"headers":[],"relativePath":"docs/guide/interface-overview.md","filePath":"docs/guide/interface-overview.md"}'),s={name:"docs/guide/interface-overview.md"};function d(c,e,l,p,m,g){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="interface-overview" tabindex="-1">Interface Overview <a class="header-anchor" href="#interface-overview" aria-label="Permalink to &quot;Interface Overview&quot;">​</a></h1><p>Motor Sound Editor separates project management from project editing on purpose. The workflow becomes easier to understand when you treat the app as two main spaces: the Home screen for managing projects, and the editor for shaping sound.</p><h2 id="home-project-lifecycle-management" tabindex="-1">Home: project lifecycle management <a class="header-anchor" href="#home-project-lifecycle-management" aria-label="Permalink to &quot;Home: project lifecycle management&quot;">​</a></h2><p><img src="'+r+'" alt="Annotated home screen"></p><p>The Home screen is the starting point of the workflow. It is mainly responsible for:</p><ul><li><strong>Project indexing</strong>: finding and reopening existing projects quickly.</li><li><strong>Asset routing</strong>: creating, importing, and opening project files.</li><li><strong>Recent-project management</strong>: organizing current work through search, sorting, and preview cards.</li></ul><h2 id="editor-workspace-parameter-editing-and-preview" tabindex="-1">Editor Workspace: parameter editing and preview <a class="header-anchor" href="#editor-workspace-parameter-editing-and-preview" aria-label="Permalink to &quot;Editor Workspace: parameter editing and preview&quot;">​</a></h2><p><img src="'+t+'" alt="Annotated editor screen"></p><p>The editor workspace is the core of the product. It focuses on:</p><ul><li><strong>Layer control</strong>: making the active track layer and its audio resource clear.</li><li><strong>Real-time preview</strong>: auditioning pitch and volume behavior at different speeds and simulator states.</li><li><strong>Data editing</strong>: adding, moving, deleting, and fine-tuning keyframes.</li></ul><h2 id="recommended-reading" tabindex="-1">Recommended reading <a class="header-anchor" href="#recommended-reading" aria-label="Permalink to &quot;Recommended reading&quot;">​</a></h2><p>After this page, continue with:</p><ol><li><a href="/Motor-Sound-Editor/docs/guide/home.html">Home and Projects</a></li><li><a href="/Motor-Sound-Editor/docs/guide/editor.html">Editor Workspace</a></li></ol>',13)])])}const w=o(s,[["render",d]]);export{v as __pageData,w as default};
